function maxChunksToSorted(arr) {
    let max_val = 0, chunks = 0;
    for (let i = 0; i < arr.length; i++) {
        max_val = Math.max(max_val, arr[i]);
        if (max_val === i) {
            chunks++;
        }
    }
    return chunks;
}
